jQuery(document).ready(function(n){const a=n.ajax({url:tpayThankYou.url,method:"POST",data:{action:"tpay_blik0_transaction_status",transactionId:tpayThankYou.transactionId,nonce:tpayThankYou.nonce},success:function(t){"correct"===t.status&&(n("#tpay_pending").hide(),n("#tpay_success").show()),"pending"===t.status&&setTimeout(a(),1500)},error:function(t){n("#tpay_pending").hide(),n("#tpay_error").show()}})});